\begin{tikzpicture}[>=stealth]
  % template objects
  % template: Sphere
  \begin{scope}[shift={(0,0)}]
    \draw[fill=blue!8, opacity=0.9] (0,0) circle (1.5);
    \draw (0,0) ellipse (1.5 and 0.513);
    \draw[tdplot_main_coords, dashed] plot[domain=0:360, samples=72, smooth] ({1.5*cos(\x)}, 0, {1.5*sin(\x)});
  \end{scope}
  % template: Hemisphere
  \begin{scope}[shift={(12,0)}]
    \draw[fill=blue!8] (-1.5,0) arc (180:0:1.5);
    \draw (0,0) ellipse (1.5 and 0.513);
  \end{scope}
  % template: Cylinder
  \begin{scope}[shift={(24,0)}]
    \begin{axis}[hide axis, view={20}{20}, axis equal image, anchor=origin, at={(0,0)}, disabledatascaling]
    \addplot3[surf, shader=interp, colormap/blackwhite, opacity=0.85, domain=0:360, y domain=0:2, samples=40, samples y=8, z buffer=sort] ({1*cos(x)}, {1*sin(x)}, y);
    \end{axis}
  \end{scope}
  % template: Cone
  \begin{scope}[shift={(36,0)}]
    \begin{axis}[hide axis, view={20}{20}, axis equal image, anchor=origin, at={(0,0)}, disabledatascaling]
    \addplot3[surf, shader=interp, colormap/blackwhite, opacity=0.85, domain=0:360, y domain=0:2, samples=40, samples y=8, z buffer=sort] ({1*(1-y/2)*cos(x)}, {1*(1-y/2)*sin(x)}, y);
    \end{axis}
  \end{scope}
  % template: Cube / box
  \begin{scope}[shift={(48,0)}]
    \draw[tdplot_main_coords, dashed] (0,0,0) -- (2,0,0) (0,0,0) -- (0,1.5,0) (0,0,0) -- (0,0,1);
