    \draw[tdplot_main_coords] (2,1.5,0) -- (2,1.5,1) -- (0,1.5,1) (2,1.5,1) -- (2,0,1);
  \end{scope}
  % template: Plane patch
  \begin{scope}[shift={(60,0)}]
    \draw[tdplot_main_coords, fill=green!12, opacity=0.9] (0,0,0) -- (2.5,0,0) -- (2.5,2,0) -- (0,2,0) -- cycle;
  \end{scope}
  % template: Torus
