    \begin{axis}[hide axis, view={20}{20}, axis equal image, anchor=origin, at={(0,0)}, disabledatascaling]
    \addplot3[surf, shader=interp, colormap/blackwhite, opacity=0.85, domain=0:360, y domain=0:360, samples=36, samples y=18, z buffer=sort] ({(1.5+0.4*cos(y))*cos(x)}, {(1.5+0.4*cos(y))*sin(x)}, {0.4*sin(y)});
    \end{axis}
  \end{scope}
