    \addplot[blue!70!black, thick, smooth] {1*(sin(deg(x)))};
    \end{axis}
  \end{scope}
  % template: Parabola
  \begin{scope}[shift={(12,0)}]
    \begin{axis}[axis lines=middle, xlabel={$x$}, ylabel={$y$}, anchor=origin, at={(0,0)}, domain=-2:2, samples=120, width=6.4cm, height=4cm]
    \addplot[blue!70!black, thick, smooth] {1*(x^2)};
    \end{axis}
  \end{scope}
  % template: Exponential
  \begin{scope}[shift={(24,0)}]
    \begin{axis}[axis lines=middle, xlabel={$x$}, ylabel={$y$}, anchor=origin, at={(0,0)}, domain=-2:1.6, samples=120, width=5.96cm, height=4cm]
    \addplot[blue!70!black, thick, smooth] {1*(exp(x))};
    \end{axis}
  \end{scope}
  % template: Logarithm
  \begin{scope}[shift={(36,0)}]
    \begin{axis}[axis lines=middle, xlabel={$x$}, ylabel={$y$}, anchor=origin, at={(0,0)}, domain=0.1:5, samples=120, width=7.39cm, height=4cm]
    \addplot[blue!70!black, thick, smooth] {1*(ln(x))};
    \end{axis}
  \end{scope}
  % template: Wavy line (snake)
  \begin{scope}[shift={(48,0)}]
    \draw[decorate, decoration={snake, amplitude=3pt, segment length=8pt}] (0,0) -- (3,0);
  \end{scope}
  % template: Coil (spring)
  \begin{scope}[shift={(60,0)}]
    \draw[decorate, decoration={coil, aspect=0.6, amplitude=5pt, segment length=5pt}] (0,0) -- (3,0);
  \end{scope}
  % template: Spiral
  \begin{scope}[shift={(72,0)}]
    \draw plot[domain=0:1080, samples=180, smooth, variable=\t] ({0.001*\t*cos(\t)}, {0.001*\t*sin(\t)});
  \end{scope}
\end{tikzpicture}

